let acc = 0.0
let stored = 0.0
let op = ""
let fresh = true

View{ width: Fill height: Fit flow: Down spacing: 12 padding: 18

  glass.Card{ display := glass.H1{text:"0" width: Fill align: Align{x:1.0}} }

  View{width:Fill height:Fit flow:Right spacing:8
    glass.GlassButton{text:"C" width:Fill height:54 on_click:|| { acc = 0.0; stored = 0.0; op = ""; fresh = true; ui.display.set_text("0") }}
    glass.GlassButton{text:"±" width:Fill height:54 on_click:|| { acc = -acc; ui.display.set_text("" + acc) }}
    glass.GlassButton{text:"%" width:Fill height:54 on_click:|| { acc = acc / 100.0; ui.display.set_text("" + acc) }}
    glass.GlassButtonProminent{text:"÷" width:Fill height:54 on_click:|| { stored = acc; acc = 0.0; op = "/"; fresh = true }}
  }

  View{width:Fill height:Fit flow:Right spacing:8
    glass.GlassButton{text:"7" width:Fill height:54 on_click:|| { acc = acc*10.0 + 7.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButton{text:"8" width:Fill height:54 on_click:|| { acc = acc*10.0 + 8.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButton{text:"9" width:Fill height:54 on_click:|| { acc = acc*10.0 + 9.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButtonProminent{text:"×" width:Fill height:54 on_click:|| { stored = acc; acc = 0.0; op = "*"; fresh = true }}
  }

  View{width:Fill height:Fit flow:Right spacing:8
    glass.GlassButton{text:"4" width:Fill height:54 on_click:|| { acc = acc*10.0 + 4.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButton{text:"5" width:Fill height:54 on_click:|| { acc = acc*10.0 + 5.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButton{text:"6" width:Fill height:54 on_click:|| { acc = acc*10.0 + 6.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButtonProminent{text:"−" width:Fill height:54 on_click:|| { stored = acc; acc = 0.0; op = "-"; fresh = true }}
  }

  View{width:Fill height:Fit flow:Right spacing:8
    glass.GlassButton{text:"1" width:Fill height:54 on_click:|| { acc = acc*10.0 + 1.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButton{text:"2" width:Fill height:54 on_click:|| { acc = acc*10.0 + 2.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButton{text:"3" width:Fill height:54 on_click:|| { acc = acc*10.0 + 3.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButtonProminent{text:"+" width:Fill height:54 on_click:|| { stored = acc; acc = 0.0; op = "+"; fresh = true }}
  }

  View{width:Fill height:Fit flow:Right spacing:8
    glass.GlassButton{text:"0" width:Fill height:54 on_click:|| { acc = acc*10.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButton{text:"00" width:Fill height:54 on_click:|| { acc = acc*100.0; fresh = false; ui.display.set_text("" + acc) }}
    glass.GlassButtonProminent{text:"=" width:Fill height:54 on_click:|| {
      let r = acc
      if op == "+" { r = stored + acc }
      if op == "-" { r = stored - acc }
      if op == "*" { r = stored * acc }
      if op == "/" { r = stored / acc }
      acc = r; op = ""; fresh = true
      ui.display.set_text("" + r)
    }}
  }
}
